import{_ as t,o as s,c as n,ag as p}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"1.5 Venn图与容斥原理","description":"","frontmatter":{},"headers":[],"relativePath":"notes/gaozhong/gaoyi/chapter01-sets/1-5-Venn图与容斥原理.md","filePath":"notes/gaozhong/gaoyi/chapter01-sets/1-5-Venn图与容斥原理.md"}'),e={name:"notes/gaozhong/gaoyi/chapter01-sets/1-5-Venn图与容斥原理.md"};function l(r,a,d,i,o,c){return s(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="_1-5-venn图与容斥原理" tabindex="-1">1.5 Venn图与容斥原理 <a class="header-anchor" href="#_1-5-venn图与容斥原理" aria-label="Permalink to &quot;1.5 Venn图与容斥原理&quot;">​</a></h1><h2 id="一、venn图-维恩图" tabindex="-1">一、Venn图（维恩图） <a class="header-anchor" href="#一、venn图-维恩图" aria-label="Permalink to &quot;一、Venn图（维恩图）&quot;">​</a></h2><p>Venn图是用封闭曲线（通常用圆）表示集合的图形工具，能直观地展示集合之间的关系与运算。</p><h3 id="基本表示" tabindex="-1">基本表示 <a class="header-anchor" href="#基本表示" aria-label="Permalink to &quot;基本表示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>图形</th><th>含义</th></tr></thead><tbody><tr><td>一个圆表示集合 $A$</td><td>$A$ 的所有元素在圆内</td></tr><tr><td>圆外区域</td><td>不属于 $A$ 的元素</td></tr><tr><td>两圆相交</td><td>交集 $A \\cap B$</td></tr><tr><td>两圆合并</td><td>并集 $A \\cup B$</td></tr></tbody></table><h3 id="常见运算图形" tabindex="-1">常见运算图形 <a class="header-anchor" href="#常见运算图形" aria-label="Permalink to &quot;常见运算图形&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  A∩B              A∪B               A的补集</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ╭───╮           ╭───╮</span></span>
<span class="line"><span> ╱ ╲ █ ╱ ╲        ╱   ╲   ╱</span></span>
<span class="line"><span>│  ██  │        ╱  ██  ╲</span></span>
<span class="line"><span> ╲ ╱ █ ╲ ╱         ╲   ╱   ╲</span></span>
<span class="line"><span>  ╰───╯           ╰───╯</span></span></code></pre></div><h2 id="二、容斥原理" tabindex="-1">二、容斥原理 <a class="header-anchor" href="#二、容斥原理" aria-label="Permalink to &quot;二、容斥原理&quot;">​</a></h2><p>容斥原理是计算有限个集合并集元素个数的公式。</p><h3 id="两个集合的容斥原理" tabindex="-1">两个集合的容斥原理 <a class="header-anchor" href="#两个集合的容斥原理" aria-label="Permalink to &quot;两个集合的容斥原理&quot;">​</a></h3><p>$$|A \\cup B| = |A| + |B| - |A \\cap B|$$</p><div class="tip custom-block"><p class="custom-block-title">含义</p><p>先相加两个集合的元素个数，其中交集部分被重复计算了一次，所以要减去一次。</p></div><details class="details custom-block"><summary>图示理解</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ╭─────────────────╮</span></span>
<span class="line"><span>   ╱      A∪B         ╲</span></span>
<span class="line"><span>  │   ╭─────────╮     │</span></span>
<span class="line"><span>  │  ╱ ■■■■■■■■  ╲     │</span></span>
<span class="line"><span>  │  │ ■■■│■■■■■ │     │  A 有 5 个元素</span></span>
<span class="line"><span>  │  │ ■■■│     │     │  B 有 4 个元素</span></span>
<span class="line"><span>  │  ╲ ■■■│■■■■■ ╱     │  A∩B 有 2 个元素</span></span>
<span class="line"><span>  │   ╰─────────╯     │</span></span>
<span class="line"><span>  ╰────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  5 + 4 - 2 = 7（A∪B 的元素个数）</span></span></code></pre></div></details><h3 id="三个集合的容斥原理" tabindex="-1">三个集合的容斥原理 <a class="header-anchor" href="#三个集合的容斥原理" aria-label="Permalink to &quot;三个集合的容斥原理&quot;">​</a></h3><p>$$|A \\cup B \\cup C| = |A| + |B| + |C| - |A \\cap B| - |B \\cap C| - |A \\cap C| + |A \\cap B \\cap C|$$</p><div class="tip custom-block"><p class="custom-block-title">记忆口诀</p><p>&quot;奇数个集合 = 加，偶数个集合 = 减&quot;</p></div><h2 id="三、应用场景" tabindex="-1">三、应用场景 <a class="header-anchor" href="#三、应用场景" aria-label="Permalink to &quot;三、应用场景&quot;">​</a></h2><p>容斥原理常用于解决以下问题：</p><ul><li>统计同时满足多个条件的元素个数</li><li>调查问卷中满足条件的人数统计</li><li>编程中集合去重计算</li></ul><h2 id="四、例题" tabindex="-1">四、例题 <a class="header-anchor" href="#四、例题" aria-label="Permalink to &quot;四、例题&quot;">​</a></h2><details class="details custom-block"><summary>点击查看例题</summary><p><strong>例1：</strong> 某班有 40 人，数学竞赛有 25 人参加，物理竞赛有 20 人参加，两项都参加的有 10 人。问：有多少人两项都不参加？</p><p><strong>解析：</strong></p><p>设 $A$ = 参加数学竞赛的人，$B$ = 参加物理竞赛的人。</p><p>$|A| = 25$，$|B| = 20$，$|A \\cap B| = 10$</p><p>$|A \\cup B| = 25 + 20 - 10 = 35$（至少参加一项的人数）</p><p>两项都不参加 = $40 - 35 = 5$ 人</p><hr><p><strong>例2：</strong> 某校高一有 200 人，其中喜欢足球的有 120 人，喜欢篮球的有 80 人，两项都喜欢的有 30 人。求只喜欢足球的有多少人？只喜欢篮球的有多少人？两项都不喜欢的有多少人？</p><p><strong>解析：</strong></p><p>只喜欢足球 = $|A| - |A \\cap B| = 120 - 30 = 90$ 人</p><p>只喜欢篮球 = $|B| - |A \\cap B| = 80 - 30 = 50$ 人</p><p>至少喜欢一项 = $120 + 80 - 30 = 170$ 人</p><p>两项都不喜欢 = $200 - 170 = 30$ 人</p><hr><p><strong>例3（三个集合）：</strong> 某班 50 人，订阅《数学报》的有 30 人，订阅《语文报》的有 25 人，订阅《英语报》的有 20 人。同时订阅《数学》和《语文》的有 10 人，同时订阅《语文》和《英语》的有 8 人，同时订阅《数学》和《英语》的有 5 人，三种都订阅的有 3 人。问三种都不订阅的有多少人？</p><p><strong>解析：</strong></p><p>设 $A, B, C$ 分别为订阅《数学》《语文》《英语》的学生集合。</p><p>$|A| = 30, |B| = 25, |C| = 20$ $|A \\cap B| = 10, |B \\cap C| = 8, |A \\cap C| = 5$ $|A \\cap B \\cap C| = 3$</p><p>$|A \\cup B \\cup C| = 30 + 25 + 20 - 10 - 8 - 5 + 3 = 55$</p><p>三种都不订阅 = $50 - 55 = -5$（人数不能为负，说明题目数据有误，实际中应检查数据）</p></details><h2 id="五、本章知识点小结" tabindex="-1">五、本章知识点小结 <a class="header-anchor" href="#五、本章知识点小结" aria-label="Permalink to &quot;五、本章知识点小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>核心内容</th></tr></thead><tbody><tr><td>集合的概念</td><td>元素、属于、常用数集</td></tr><tr><td>集合的表示</td><td>列举法、描述法、区间</td></tr><tr><td>集合的关系</td><td>子集、真子集、空集、相等</td></tr><tr><td>集合的运算</td><td>交集、并集、补集</td></tr><tr><td>Venn图</td><td>直观表示集合关系与运算</td></tr><tr><td>容斥原理</td><td>计算并集元素个数</td></tr></tbody></table>`,23)])])}const $=t(e,[["render",l]]);export{u as __pageData,$ as default};
